import{_ as e,c as a,o as n,aj as i}from"./chunks/framework.SxNn8fcm.js";const p=JSON.parse('{"title":"What is Scanic?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1782820720000}'),r={name:"guide/introduction.md"};function s(l,t,o,d,c,g){return n(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="what-is-scanic" tabindex="-1">What is Scanic? <a class="header-anchor" href="#what-is-scanic" aria-label="Permalink to &quot;What is Scanic?&quot;">​</a></h1><p>Scanic is a high-performance document scanner library for JavaScript. It finds the edges of a document in a photo, then straightens and crops it into a clean, flat image — the same &quot;scan from a photo&quot; experience you get in mobile scanner apps, but running entirely in the browser or in Node.js.</p><p>It combines <strong>Rust-powered WebAssembly</strong> for the pixel-crunching parts (blur, edge detection, morphology) with a <strong>GPU-accelerated Canvas</strong> warp for perspective correction, giving near-native performance in a tiny package.</p><h2 id="why-scanic" tabindex="-1">Why Scanic? <a class="header-anchor" href="#why-scanic" aria-label="Permalink to &quot;Why Scanic?&quot;">​</a></h2><p>Web document scanning has traditionally forced a trade-off:</p><ul><li><strong>OpenCV.js</strong> is powerful but ships a <strong>30MB+</strong> download.</li><li><strong>Pure JS</strong> libraries are lightweight but struggle with real-time performance and complex transforms.</li></ul><p>Scanic bridges the gap:</p><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">Scanic</th><th style="text-align:left;">jscanify</th><th style="text-align:left;">OpenCV.js</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Download size</strong></td><td style="text-align:left;"><strong>~100KB</strong></td><td style="text-align:left;">~31MB</td><td style="text-align:left;">~30MB</td></tr><tr><td style="text-align:left;"><strong>Perspective speed</strong></td><td style="text-align:left;"><strong>~10ms</strong></td><td style="text-align:left;">~200ms</td><td style="text-align:left;">~5ms</td></tr><tr><td style="text-align:left;"><strong>WASM optimized</strong></td><td style="text-align:left;">✅</td><td style="text-align:left;">❌</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;"><strong>GPU acceleration</strong></td><td style="text-align:left;">✅</td><td style="text-align:left;">❌</td><td style="text-align:left;">❌</td></tr><tr><td style="text-align:left;"><strong>TypeScript</strong></td><td style="text-align:left;">✅</td><td style="text-align:left;">❌</td><td style="text-align:left;">✅</td></tr></tbody></table><h2 id="what-you-can-build" tabindex="-1">What you can build <a class="header-anchor" href="#what-you-can-build" aria-label="Permalink to &quot;What you can build&quot;">​</a></h2><ul><li><strong>Receipt / document capture</strong> in web forms — upload a photo, get a clean scan.</li><li><strong>Real-time webcam scanning</strong> with live edge overlays (see the <a href="/scanic/guide/web#real-time-scanning"><code>Scanner</code></a> class).</li><li><strong>Server-side batch processing</strong> of uploaded images in <a href="/scanic/guide/nodejs">Node.js</a>.</li><li><strong>Desktop apps</strong> via <a href="/scanic/guide/electron">Electron</a>.</li></ul><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/scanic/guide/getting-started">Getting Started</a> — install and run your first scan, with a live playground.</li><li><a href="/scanic/guide/how-it-works">How It Works</a> — a short tour of the detection pipeline.</li><li><a href="/scanic/api/reference">API Reference</a> — every function and option.</li></ul>',12)])])}const f=e(r,[["render",s]]);export{p as __pageData,f as default};
